/* PasstheEPPP — Question Bank Batch 51
   90 new questions — Treatment advances, Neuropsych, Ethics edge cases, Clinical subtleties */
(function(){
    if (typeof EPPPData === 'undefined') return;

    const batch51 = [
        // === Treatment Advances (20) ===
        {domainId:6, q:"Prolonged Exposure (PE) therapy for PTSD involves:", options:["Strictly avoiding any direct discussion of trauma reminders to fundamentally prevent overwhelming affective psychological destabilization","Repeated, detailed imaginal exposure to the trauma memory PLUS in-vivo exposure to avoided situations to promote habituation and emotional processing","Exclusively prioritizing intensive progressive muscle relaxation techniques before attempting any exploratory cognitive restructuring interventions","Focusing entirely upon developing future-oriented cognitive restructuring without addressing explicit sensory trauma memory characteristics"], answer:1, difficulty:"medium", rationale:"Correct: (B) PE (Foa): four components — psychoeducation, breathing retraining, in-vivo exposure (approaching safe situations avoided due to PTSD), imaginal exposure (repeatedly recounting the trauma aloud). Processing promotes habituation and corrects erroneous cognitions about danger.\n\nWhy others are wrong:\n(A) Avoidance maintains PTSD; PE counters avoidance\n(C) Relaxation is taught but exposure is the active mechanism\n(D) Cognitive Processing Therapy (CPT) emphasizes cognitive restructuring"},
        {domainId:6, q:"Interpersonal Therapy (IPT) focuses on:", options:["Extensively analyzing repressed childhood memories exploring foundational unconscious psychosexual developmental conflict patterns","Current interpersonal problems in four domains: grief, role disputes, role transitions, and interpersonal deficits","Primarily identifying and resolving deep unconscious conflicts originating exclusively during formative early developmental stages","Focusing entirely upon structured behavioral activation assignments designed systematically to increase environmental reinforcement"], answer:1, difficulty:"medium", rationale:"Correct: (B) IPT (Klerman & Weissman): time-limited (12-16 sessions), focusing on current interpersonal context of depression. Four problem areas: grief (complicated bereavement), role disputes (conflicts), role transitions (life changes), interpersonal deficits (social isolation). Strong evidence for depression.\n\nWhy others are wrong:\n(A) IPT is present-focused, not past-focused\n(C) IPT addresses interpersonal patterns, not unconscious conflicts (psychodynamic)\n(D) Behavioral activation is a separate treatment approach"},
        {domainId:6, q:"Acceptance and Commitment Therapy (ACT) uses the hexaflex model including:", options:["Only emphasizing total unconditional acceptance surrounding distressing internal private psychological cognitive events","Six core processes: acceptance, cognitive defusion, being present, self-as-context, values, and committed action — all serving psychological flexibility","Focusing exclusively upon mindfulness meditation techniques designed explicitly to eliminate clinical affective distress","Prioritizing strictly measurable overt behavioral change strategies independently of any internal cognitive processing"], answer:1, difficulty:"medium", rationale:"Correct: (B) ACT hexaflex: (1) Acceptance (open to internal experiences), (2) Cognitive defusion (unhooking from thoughts), (3) Present moment contact (mindfulness), (4) Self-as-context (observer self), (5) Values (what matters), (6) Committed action (behavior aligned with values). Goal: psychological flexibility.\n\nWhy others are wrong:\n(A) Acceptance is one of six processes\n(C) Mindfulness (being present) is one component\n(D) Committed action is one component — ACT integrates experiential and behavioral approaches"},
        {domainId:6, q:"Dialectical Behavior Therapy (DBT) skill modules include:", options:["Only intensive unstructured individual mindfulness meditation focusing completely upon physiological autonomic awareness","Mindfulness, distress tolerance, emotion regulation, and interpersonal effectiveness","Focusing exclusively upon cognitive anger management techniques resolving deeply rooted interpersonal hostility","Exclusively utilizing traditional cognitive restructuring methods targeting specific irrational schematic beliefs"], answer:1, difficulty:"easy", rationale:"Correct: (B) DBT (Linehan): four skill modules taught in skills group. Mindfulness (core awareness). Distress tolerance (surviving crises without making them worse — TIPP, radical acceptance). Emotion regulation (understanding and changing emotions). Interpersonal effectiveness (DEAR MAN, GIVE, FAST).\n\nWhy others are wrong:\n(A) Mindfulness is one of four modules\n(C) Anger management isn't a separate DBT module\n(D) DBT uses behavioral strategies more than cognitive restructuring"},
        {domainId:6, q:"Motivational Interviewing (MI) uses which key strategies?", options:["Forceful direct confrontation highlighting destructive behavioral patterns explicitly ensuring maximum clinical accountability","OARS: Open-ended questions, Affirmations, Reflections, and Summaries — emphasizing collaboration over confrontation","Lecturing the ambivalent client extensively concerning severe physiological consequences stemming from persistent substance abuse","Authoritatively imposing structured behavioral solutions directing clients precisely toward mandated recovery pathways"], answer:1, difficulty:"easy", rationale:"Correct: (B) MI (Miller & Rollnick): collaborative, person-centered approach to strengthen motivation for change. OARS is the communication toolkit. Spirit: partnership, acceptance, compassion, evocation. Elicit-provide-elicit framework. Addresses ambivalence through exploring discrepancy.\n\nWhy others are wrong:\n(A) MI explicitly rejects the confrontational approach (the 'righting reflex')\n(C) MI draws out the client's own change talk, not lectures\n(D) Client autonomy is a core MI value"},
        {domainId:6, q:"Cognitive Processing Therapy (CPT) for PTSD targets:", options:["Exclusively reducing overt behavioral avoidance patterns utilizing graduated systematic situational exposure hierarchies","Maladaptive beliefs ('stuck points') about the trauma, self, and world — using Socratic questioning and cognitive worksheets","Primarily establishing deep physiological relaxation responses directly counteracting chronic autonomic hyperarousal","Focusing entirely upon recurrent prolonged imaginal exposure precisely targeting isolated fragmented acoustic trauma memories"], answer:1, difficulty:"medium", rationale:"Correct: (B) CPT (Resick): identifies and challenges stuck points — dysfunctional beliefs arising from the trauma (e.g., 'It was my fault,' 'The world is completely dangerous'). Uses ABC worksheets and Challenging Questions worksheets. 12-session protocol. Dismantling studies show the cognitive component alone is effective.\n\nWhy others are wrong:\n(A) CPT primarily targets cognitions, though behavioral changes often follow\n(C) Relaxation is not a primary CPT component\n(D) CPT is cognitive, not exposure-based (though homework may involve approaching reminders)"},
        {domainId:6, q:"Solution-Focused Brief Therapy (SFBT) uses:", options:["Extensive exhaustive historical problem analysis investigating foundational origins surrounding presenting clinical complaints","The miracle question, scaling questions, exception-finding, and coping questions — focusing on solutions rather than problems","Primarily psychodynamic symbolic dream interpretation analyzing deeply repressed unconscious interrelational conflicts","Exclusively emphasizing targeted psychopharmacological medication management reducing severe acute neurological symptomatology"], answer:1, difficulty:"easy", rationale:"Correct: (B) SFBT (de Shazer, Berg): future-oriented. Miracle question ('If a miracle happened tonight...'). Scaling questions ('On a 1-10 scale...'). Exception finding ('When is the problem absent/less?'). Coping questions ('How have you managed?'). Emphasis on client strengths and resources.\n\nWhy others are wrong:\n(A) SFBT deliberately minimizes problem-focused discussions\n(C) Dream interpretation → psychoanalytic approaches\n(D) SFBT is a psychotherapy, not pharmacotherapy"},
        {domainId:6, q:"In Gottman's couples therapy, the 'Four Horsemen' that predict divorce are:", options:["Unconditional empathy, mutual trust, deep foundational respect, and enduring structural relationship commitment","Criticism, contempt, defensiveness, and stonewalling","Exclusively isolated superficial communication problems easily resolved utilizing standard active listening exercises","Intense anger, profound sadness, debilitating fear, and overwhelming pervasive spontaneous reactive joy"], answer:1, difficulty:"medium", rationale:"Correct: (B) Four Horsemen (Gottman): Criticism (global attacks on partner's character), Contempt (disrespect, mockery — the worst predictor), Defensiveness (counter-attacking or playing victim), Stonewalling (shutting down, withdrawing). Antidotes: gentle start-up, expressing appreciation, accepting responsibility, self-soothing.\n\nWhy others are wrong:\n(A) These are positive relationship elements, not destructive patterns\n(C) The Four Horsemen are specific destructive patterns\n(D) These are emotions, not interactional patterns"},
        {domainId:6, q:"Narrative therapy views problems as:", options:["Inherent stable internal biological defects fundamentally defining the individual's core enduring psychological character","Separate from the person ('the person is NOT the problem; the problem is the problem') — using externalization and re-authoring","Entirely rigid unchangeable predetermined fatalistic historical destinies strictly immune to psychological intervention","Originating exclusively within fundamental biological neurochemical neurotransmitter imbalances requiring specialized pharmaceutical treatment"], answer:1, difficulty:"medium", rationale:"Correct: (B) Narrative therapy (White & Epston): externalizes problems (e.g., 'When does Anxiety visit you?'). Deconstructs problem-saturated stories. Finds unique outcomes (exceptions). Re-authors preferred narratives. Sociopolitical awareness — problems are embedded in cultural discourses.\n\nWhy others are wrong:\n(A) Narrative therapy explicitly rejects pathologizing the person\n(C) Stories can be re-authored — change is always possible\n(D) Problems are understood as socially constructed narratives"},
        {domainId:6, q:"Systematic desensitization (Wolpe) combines:", options:["Extensive sustained unstructured flooding exposing clients directly toward overwhelmingly distressing environmental stimuli","Progressive relaxation with a hierarchy of feared stimuli, working from least to most anxiety-provoking through reciprocal inhibition","Exclusively utilizing highly targeted fast-acting anxiolytic medication explicitly regulating severe physiological panic","Primarily focusing upon rational cognitive therapy systematically dismantling conscious catastrophic ideation patterns"], answer:1, difficulty:"easy", rationale:"Correct: (B) Systematic desensitization: (1) Learn deep relaxation, (2) Construct a fear hierarchy (SUDs 0-100), (3) Pair relaxation with each hierarchy item, moving up as anxiety diminishes. Reciprocal inhibition: relaxation and anxiety can't coexist. Gradual counterconditioning.\n\nWhy others are wrong:\n(A) Flooding involves immediate, prolonged exposure to the most feared stimulus — no hierarchy\n(C) Medication is not part of systematic desensitization\n(D) It's a behavioral technique based on classical conditioning principles"},
        {domainId:6, q:"Internal Family Systems (IFS, Schwartz) conceptualizes the mind as:", options:["A monolithic undifferentiated singular conceptual entity lacking any dynamic internal interactive structural variation","A system of 'parts' (Exiles, Managers, Firefighters) organized around a core Self that has inherent wisdom and compassion","Operating exclusively around structural psychodynamic id, ego, and superego interpersonal intrapsychic defensive mechanisms","Functioning seamlessly governed entirely by rational conscious deliberate thoughts systematically suppressing emotion"], answer:1, difficulty:"hard", rationale:"Correct: (B) IFS: subpersonalities. Exiles: carry pain/trauma (vulnerable parts). Managers: protect proactively (controlling, perfectionistic). Firefighters: react to exile activation (impulsive behaviors, substance use, dissociation). Self: the compassionate, curious, calm core that can heal parts.\n\nWhy others are wrong:\n(A) IFS explicitly views the mind as multiple parts\n(C) Id/ego/superego is Freud's structural model — IFS is different\n(D) Parts include unconscious protective strategies"},
        {domainId:6, q:"Relapse prevention (Marlatt) distinguishes between:", options:["Only focusing upon total catastrophic comprehensive behavioral relapse indicating definitive overall therapeutic failure","A lapse (initial slip) and a relapse (return to pre-treatment behavior), using the Abstinence Violation Effect concept","Focusing exclusively upon complete permanent lifelong recovery strictly demanding absolute continuous unbroken abstinence","Establishing rigid dichotomous categorical boundaries separating pure successful cure from absolute clinical failure"], answer:1, difficulty:"medium", rationale:"Correct: (B) Marlatt: a lapse (single use) doesn't have to become a relapse (full return). The Abstinence Violation Effect (AVE): internal attribution for a lapse ('I'm a failure') → guilt → full relapse. Treatment: identify high-risk situations, develop coping strategies, reframe lapses as learning.\n\nWhy others are wrong:\n(A) The key distinction is between lapse and relapse\n(C) The model addresses the process between abstinence and relapse\n(D) Addiction is a chronic condition — cure/no cure framing is less applicable"},
        {domainId:6, q:"Neurofeedback (EEG biofeedback) involves:", options:["Highly invasive irreversible structural brain surgery explicitly designed altering underlying anatomical white matter neural pathways","Training individuals to modify their brain wave patterns through real-time feedback of EEG activity","Strictly relying exclusively upon heavy psychiatric pharmacological medication systematically suppressing severe neurological hyperarousal","Utilizing only traditional unstructured reflective talk therapy discussing deeply rooted historical familial complex relationships"], answer:1, difficulty:"medium", rationale:"Correct: (B) Neurofeedback: operant conditioning of brain activity. EEG electrodes measure brain waves; the person receives visual/auditory feedback when producing desired patterns. Used for ADHD (increase beta, decrease theta), anxiety, epilepsy, TBI. Growing evidence base, though controversial.\n\nWhy others are wrong:\n(A) Neurofeedback is non-invasive — no surgery\n(C) It's a behavioral/technological intervention, not pharmacological\n(D) It uses EEG technology, not verbal processing"},
        {domainId:6, q:"Group therapy factors identified by Yalom include:", options:["Exclusively emphasizing dramatic explosive unstructured affective emotional catharsis resolving deep repressed collective conflict","Universality, altruism, instillation of hope, imparting information, corrective recapitulation of the family, socializing techniques, imitative behavior, interpersonal learning, group cohesiveness, catharsis, existential factors","Focusing entirely upon structured didactic socialization training exercises exclusively modeling normative non-verbal expressive gestures","Primarily utilizing formal rigid academic educational instruction targeting specific complex factual generalized psychological content"], answer:1, difficulty:"medium", rationale:"Correct: (B) Yalom's 11 therapeutic factors operate uniquely in groups. Most researched: group cohesiveness (therapeutic alliance equivalent), interpersonal learning (feedback + corrective emotional experience), universality ('I'm not the only one'). Different factors operate at different group stages.\n\nWhy others are wrong:\n(A) Catharsis is one of 11 factors\n(C) Socializing techniques are one factor among many\n(D) Imparting information is one factor among many"},
        {domainId:6, q:"Functional Analytic Psychotherapy (FAP) focuses on:", options:["Exclusively conducting rigorous extensive individualized structural behavioral analysis precisely examining past historical conditioned contingencies","In-session clinically relevant behaviors (CRBs) — therapeutic improvement occurs through the real-time interpersonal process between therapist and client","Focusing strictly upon highly structured rigorous systematic outpatient environmental homework assignments practiced diligently between regular sessions","Providing extensive detailed formal cognitive psychoeducation consistently lecturing clients concerning abstract rational conceptual principles"], answer:1, difficulty:"hard", rationale:"Correct: (B) FAP (Kohlenberg & Tsai): CRB1 (problematic behaviors in session), CRB2 (improved behaviors in session), CRB3 (client's interpretations). The therapist naturally reinforces CRB2s as they occur in the therapeutic relationship — the therapy relationship IS the mechanism of change.\n\nWhy others are wrong:\n(A) While informed by behavioral analysis, the focus is on in-session interpersonal process\n(C) The therapeutic action occurs in-session, not primarily through homework\n(D) The mechanism is experiential/interpersonal, not didactic"},

        // === Neuropsychology (15) ===
        {domainId:5, q:"The Trail Making Test (TMT) assesses:", options:["Exclusively evaluating long-term semantic memory consolidation and retrieval processes across extended temporal delays","Part A: visual scanning and psychomotor speed; Part B: cognitive flexibility and set-shifting (alternating between numbers and letters)","Primarily functioning as a comprehensive diagnostic tool specifically measuring expressive and receptive language fluency","Focusing entirely upon measuring fundamental gross motor coordination and overarching proprioceptive structural balance"], answer:1, difficulty:"medium", rationale:"Correct: (B) TMT Part A: connect numbered circles in order (1-2-3...). Part B: alternate numbers and letters (1-A-2-B-3-C...). Part B requires executive function — switching between sets. B-A difference score isolates the executive component. Sensitive to multiple neurological conditions.\n\nWhy others are wrong:\n(A) TMT measures processing speed and executive function, not memory\n(C) Language is not directly assessed\n(D) While visual scanning is involved, cognitive flexibility is a key component"},
        {domainId:5, q:"The Wisconsin Card Sorting Test (WCST) primarily measures:", options:["Declarative declarative biographical memory capacity requiring explicit conscious retrieval mechanisms","Executive function — specifically cognitive flexibility, abstract reasoning, and the ability to shift strategies in response to changing feedback","Receptive language comprehension strictly involving complex grammatical semantic linguistic structures","Fine motor structural coordination tasks involving precisely timed highly regulated manual dexterity"], answer:1, difficulty:"medium", rationale:"Correct: (B) WCST: sort cards by color, form, or number. Sorting rule changes without warning — must shift based on feedback. Perseverative errors (continuing the old rule) indicate prefrontal dysfunction, particularly dorsolateral PFC. Sensitive to frontal lobe damage.\n\nWhy others are wrong:\n(A) WCST measures executive function, not memory\n(C) No language comprehension component\n(D) Not a motor speed measure"},
        {domainId:5, q:"Hemispatial neglect (unilateral neglect) most commonly results from:", options:["Left hemisphere temporal damage systematically producing severe structural receptive aphasic deficits","RIGHT parietal lobe damage, causing inattention to the LEFT side of space","Bilateral occipital damage resulting primarily in complete cortical visual blindness presentations","Isolated cerebellar damage heavily disrupting fundamental automated motor coordination sequencing"], answer:1, difficulty:"medium", rationale:"Correct: (B) Right parietal (especially inferior parietal lobule/temporoparietal junction) damage → left-sided neglect. The right hemisphere attends to both visual fields; the left hemisphere only attends to the right. So left damage rarely causes right neglect (right hemisphere compensates), but right damage causes left neglect.\n\nWhy others are wrong:\n(A) Left hemisphere damage rarely produces significant neglect\n(C) Occipital damage → visual field cuts (hemianopia), not neglect\n(D) Cerebellar damage → ataxia, not neglect"},
        {domainId:5, q:"The Halstead-Reitan Neuropsychological Battery includes:", options:["Only one single comprehensive fluid intelligence test estimating broad overarching global cognitive capacity","Multiple subtests including the Category Test, Tactual Performance Test, Finger Tapping Test, and Trails A/B — providing comprehensive brain function assessment","Exclusively unstructured projective personality measures revealing unconscious psychosocial interrelational motives","Focusing strictly upon highly specialized localized working memory capacity utilizing specific span tasks"], answer:1, difficulty:"medium", rationale:"Correct: (B) Halstead-Reitan: comprehensive fixed battery. Category Test (abstract reasoning), TPT (spatial memory, tactile problem-solving), Finger Tapping (motor speed), Seashore Rhythm Test (auditory perception), Speech Sounds Perception. Generates an Impairment Index. Complemented by WAIS and MMPI.\n\nWhy others are wrong:\n(A) It's a multi-test battery\n(C) Intelligence is assessed separately (often with WAIS)\n(D) Memory is one component among many cognitive domains tested"},
        {domainId:5, q:"Prosopagnosia is:", options:["A severe expressive language impairment significantly hindering verbal communication capabilities","The inability to recognize familiar faces, typically resulting from damage to the fusiform face area (fusiform gyrus) in the temporal lobe","A generalized comprehensive progressive systemic neurodegenerative declarative memory disorder","An essential neurodevelopmental movement disorder disrupting voluntary muscular somatic control"], answer:1, difficulty:"medium", rationale:"Correct: (B) Prosopagnosia: 'face blindness.' Acquired (brain damage) or developmental (congenital). Fusiform face area (FFA) in the right fusiform gyrus is specialized for face processing. Patients may recognize people by voice, clothing, or context. Can still identify objects.\n\nWhy others are wrong:\n(A) Language → aphasia\n(C) It's a visual recognition deficit, not a general memory disorder\n(D) Movement disorders → basal ganglia/cerebellar conditions"},
        {domainId:5, q:"The Stroop Test measures:", options:["Exclusively evaluating baseline rudimentary fundamental reading processing speed acquisition metrics","Selective attention and response inhibition — the ability to suppress automatic responses (reading) in favor of a controlled response (naming ink color)","Primarily mapping pure sensory physiological peripheral color vision perceptual threshold capacities","Focusing entirely upon measuring long-term structural semantic declarative memory encoding skills"], answer:1, difficulty:"easy", rationale:"Correct: (B) Stroop: name the ink color of color words (e.g., 'RED' printed in blue ink → say 'blue'). The Stroop effect (slower for incongruent trials) reflects the automaticity of reading and the cognitive control needed to inhibit it. Sensitive to frontal lobe dysfunction.\n\nWhy others are wrong:\n(A) The Stroop involves reading suppression, not reading speed\n(C) It's about cognitive control, not just color perception\n(D) The Stroop measures attention/inhibition, not memory"},
        {domainId:5, q:"The corpus callosum connects:", options:["The central cerebral cortex structurally directly downwards into the descending spinal cord pathways","The left and right cerebral hemispheres, allowing interhemispheric communication","The posterior cerebellar hemispheres structurally connecting heavily toward the primary motor cortex","Uniquely isolating functioning strictly within localized interconnected prefrontal cortical regions"], answer:1, difficulty:"easy", rationale:"Correct: (B) Corpus callosum: the largest white matter structure, containing ~200 million axons connecting left and right hemispheres. Split-brain patients (callosotomy for epilepsy) demonstrate lateralized functions — information presented to one hemisphere can't transfer to the other.\n\nWhy others are wrong:\n(A) Brainstem connects brain to spinal cord\n(C) The corpus callosum is cortical, connecting hemispheres\n(D) It connects ALL cortical regions across hemispheres, not just frontal"},
        {domainId:5, q:"The Glasgow Coma Scale (GCS) measures:", options:["Comprehensive standardized quantitative intellectual psychometric cognitive processing baseline capacity","Consciousness level after brain injury using eye opening, verbal response, and motor response — scores from 3 (deepest coma) to 15 (fully alert)","Clinical enduring stable trait-level pervasive persistent major depressive affective symptomatology","Acute systematic state-level overwhelming physiological systemic autonomic hyperarousal anxiety"], answer:1, difficulty:"easy", rationale:"Correct: (B) GCS: three components. Eye opening (4 levels: spontaneous → none). Verbal response (5 levels: oriented → none). Motor response (6 levels: obeys commands → none). Total 3-15. ≤8 = severe TBI, 9-12 = moderate, 13-15 = mild. Used in emergency assessment.\n\nWhy others are wrong:\n(A) GCS measures consciousness, not intelligence\n(C) Depression → BDI, PHQ-9\n(D) Anxiety → BAI, GAD-7"},
        {domainId:5, q:"Retrograde amnesia involves:", options:["An absolute pervasive persistent neurological inability identifying and forming any new explicit memories","Loss of memories for events that occurred BEFORE the brain injury or onset of amnesia","Exclusively isolated superficial transient completely harmless brief benign momentary cognitive lapses","Significantly pathologically highly enhanced extraordinary declarative structural memory hyper-recall"], answer:1, difficulty:"easy", rationale:"Correct: (B) Retrograde amnesia: loss of pre-injury memories. Often follows Ribot's law — most recent memories are most vulnerable; remote memories may be preserved (temporal gradient). Anterograde amnesia: inability to form NEW memories after the event. H.M. (Molaison) had severe anterograde amnesia.\n\nWhy others are wrong:\n(A) New memory formation inability → anterograde amnesia\n(C) Retrograde amnesia can be extensive, not just brief lapses\n(D) Amnesia involves memory loss, not enhancement"},
        {domainId:5, q:"Executive functions are primarily associated with:", options:["The posterior visual occipital lobe strictly processing primary neurobiological spatial sensory data","The prefrontal cortex — including planning, decision-making, working memory, inhibition, cognitive flexibility, and self-monitoring","The foundational subcortical cerebellar structures orchestrating complex voluntary motor coordination","The fundamental elementary survival-oriented brainstem structures regulating autonomic functioning"], answer:1, difficulty:"easy", rationale:"Correct: (B) PFC subregions: dorsolateral → working memory, planning, cognitive flexibility. Ventromedial → decision-making, emotional regulation, somatic markers (Damasio). Orbitofrontal → social behavior, impulse control. Anterior cingulate → error monitoring, conflict detection.\n\nWhy others are wrong:\n(A) Occipital lobe → visual processing\n(C) Cerebellum → motor coordination, balance\n(D) Brainstem → vital functions (breathing, heart rate)"},
        {domainId:5, q:"The California Verbal Learning Test (CVLT) measures:", options:["Exclusively foundational basic superficial auditory acoustic sensory neurological recognition memory","Multiple aspects of verbal learning and memory: learning rate, recall strategies, proactive/retroactive interference, retention, and recognition","Primarily fine detailed precise unilateral standardized manipulative somatic manual motor function","Focusing completely upon strictly isolating continuous persistent visuospatial constructional memory"], answer:1, difficulty:"medium", rationale:"Correct: (B) CVLT-3: 16-item shopping list presented over 5 learning trials, then an interference list, then short-delay and long-delay free recall and cued recall, plus recognition. Rich data: learning slope, semantic clustering, serial position effects, susceptibility to interference.\n\nWhy others are wrong:\n(A) The CVLT measures multiple memory processes, not just recognition\n(C) It measures verbal memory, not motor function\n(D) It's verbal, not visual (Rey Complex Figure Test is visual)"},
        {domainId:5, q:"Anosognosia refers to:", options:["A severe pathologically enhanced disproportionate anxious preoccupying self-awareness mechanism","Lack of awareness or denial of one's own neurological deficit, such as not recognizing paralysis of a limb","A profound structural neurodevelopmental expressive semantic syntactic linguistic speech disorder","A pervasive persistent neurobiological clinically significant affective emotional mood disorder"], answer:1, difficulty:"medium", rationale:"Correct: (B) Anosognosia: neurological unawareness of impairment. Common after right hemisphere stroke (denied left hemiplegia). Also seen in Alzheimer's (unawareness of memory loss), schizophrenia (unawareness of illness). Important for treatment planning — affects compliance.\n\nWhy others are wrong:\n(A) It's the opposite — lack of awareness\n(C) Language disorders → aphasia\n(D) It's a neurological phenomenon, though it affects many conditions"},
        
        // === Ethics Edge Cases (10) ===
        {domainId:8, q:"When a client presents with suicidal ideation, the psychologist's FIRST priority should be:", options:["Immediately comprehensively documenting every single historical detail ensuring absolute maximum legal professional liability protection","Assessing the level of risk — including plan, means, intent, risk factors, and protective factors — to determine the appropriate level of intervention","Automatically unconditionally breaking confidentiality protocols immediately initiating involuntary commitment procedures without evaluation","Rapidly referring the complex high-risk client toward another independent mental health provider minimizing personal legal exposure"], answer:1, difficulty:"medium", rationale:"Correct: (B) Risk assessment first: suicidal ideation → plan → means → intent → history of attempts → protective factors. This assessment guides the intervention level (safety planning, increased sessions, hospitalization). Documentation and notification follow assessment, not precede it.\n\nWhy others are wrong:\n(A) Documentation is important but follows clinical assessment\n(C) Confidentiality may need to be broken, but only after risk assessment determines the appropriate action\n(D) Referral may be appropriate but not the first step"},
        {domainId:8, q:"The ethical principle of nonmaleficence requires psychologists to:", options:["Exclusively provide medically necessary essential psychiatric pharmacological treatment interventions optimizing measurable physiological outcomes","Take care not to cause harm, including through omission, and to minimize unavoidable harm in professional activities","Completely ignore potential hypothetical minor clinical harms prioritizing broader theoretical experimental scientific empirical discoveries","Consistently strictly prioritize publishing comprehensive rigorous experimental academic research findings over individualized client welfare"], answer:1, difficulty:"easy", rationale:"Correct: (B) Nonmaleficence ('do no harm'): active responsibility to avoid practices, methods, or interventions that cause harm. Includes harm from: biased assessments, inappropriate interventions, dual relationships, breaches of confidentiality, cultural insensitivity, or failure to act.\n\nWhy others are wrong:\n(A) Nonmaleficence is specifically about avoiding harm\n(C) Psychologists must actively work to prevent harm\n(D) Client welfare always takes priority in clinical work"},
        {domainId:8, q:"A psychologist who receives a subpoena for client records should:", options:["Instantly unconditionally release all requested sensitive therapeutic historical documentation immediately complying fully without hesitation","Consult with an attorney, notify the client, and determine whether the subpoena is valid and whether privilege applies before releasing any information","Systematically securely meticulously destroy all requested clinical records permanently avoiding any potential subsequent legal discovery","Completely completely uniformly absolutely ignore the incoming legal document avoiding unnecessary engagement within the adversarial process"], answer:1, difficulty:"medium", rationale:"Correct: (B) Subpoena ≠ court order. Steps: (1) Consult an attorney, (2) Notify the client, (3) Determine if a valid authorization/waiver exists, (4) Seek to quash or limit the subpoena if appropriate, (5) Only a court order compels disclosure. Never automatically release records upon subpoena.\n\nWhy others are wrong:\n(A) Immediate release violates client confidentiality and privilege\n(C) Destroying records is illegal (obstruction, spoliation)\n(D) Ignoring a subpoena can result in contempt of court"},
        {domainId:8, q:"When treating a minor, confidentiality generally belongs to:", options:["Exclusively fundamentally independently the highly trained individual clinical treating therapist completely dictating all informational access parameters","The parent/guardian has access rights, but the psychologist balances parental rights with the therapeutic needs of the minor","Solely uniquely completely exclusively the individual child patient strictly forbidding any external parental guardian awareness whatsoever","Categorically fundamentally exclusively the child's encompassing educational school organizational academic structural institutional system administration"], answer:1, difficulty:"medium", rationale:"Correct: (B) Minors: parents generally hold the right to access records and information. However, best practice: negotiate confidentiality agreements at the start — discussing with parents what will/won't be shared. Some jurisdictions grant teens confidentiality for substance abuse, sexual health, or mental health.\n\nWhy others are wrong:\n(A) The therapist doesn't hold confidentiality rights\n(C) Generally, minors don't have full confidentiality from parents (with some exceptions)\n(D) Schools have separate FERPA protections"},
        {domainId:8, q:"The Goldwater Rule in psychology/psychiatry refers to:", options:["An established meticulously systematically researched highly rigorous gold standard benchmark guiding specific empirically supported clinical therapy","The ethical principle that mental health professionals should not publicly diagnose individuals they have not personally examined","A comprehensive fundamentally detailed highly structured theoretical treatment framework utilized explicitly managing severe acute crisis interventions","An intricate formally established highly systematic standardized institutional billing regulation maximizing legitimate financial clinical reimbursement"], answer:1, difficulty:"medium", rationale:"Correct: (B) Goldwater Rule (APA Medical, Section 7.3): arose after psychiatrists publicly diagnosed Barry Goldwater in 1964. It's unethical to offer professional opinions about public figures without examination and proper authorization. Applies to both psychiatrists and psychologists (APA Ethics Standard 9.01).\n\nWhy others are wrong:\n(A) It's an ethical standard, not a treatment benchmark\n(C) It's about professional opinions, not treatment guidelines\n(D) It's about public commentary, not billing"},
        {domainId:8, q:"Informed consent for therapy must include:", options:["Exclusively conveying only the explicit individual primary treating clinician's professional formal credentialing historical structural educational background","The nature of treatment, expected benefits and risks, alternatives, limits of confidentiality, fees, and the client's right to withdraw at any time","Primarily completely focusing entirely upon detailing comprehensive standard institutional overarching complicated financial billing procedures","Exclusively concentrating deeply entirely upon precisely systematically establishing exact complex legal extensive confidentiality limitations"], answer:1, difficulty:"easy", rationale:"Correct: (B) APA Standard 10.01: adequate informed consent includes nature and anticipated course of therapy, fees, involvement of third parties, limits of confidentiality. Ongoing process — not just a form at intake. Must be appropriate to the client's capacity to understand.\n\nWhy others are wrong:\n(A)(C)(D) Each is only one component of complete informed consent"},
        {domainId:8, q:"When a psychologist suspect elder abuse, they must:", options:["Strictly absolutely completely preserve fundamental clinical interrelational confidentiality maintaining absolute therapeutic professional silence","Follow state mandatory reporting laws — most states require reporting suspected elder abuse to Adult Protective Services (APS) or law enforcement","Exclusively confidentially discreetly thoroughly privately discuss these profound concerns solely among specific trusted close professional colleagues","Wait patiently conservatively continuously until obtaining incontrovertible definitive unassailable explicit objective physical forensic proof"], answer:1, difficulty:"easy", rationale:"Correct: (B) Most states include psychologists as mandated reporters for elder abuse (physical, sexual, emotional, financial, neglect). Reporting is based on reasonable suspicion, not certainty. The reporter is typically protected from civil liability for good-faith reports.\n\nWhy others are wrong:\n(A) Mandatory reporting overrides confidentiality\n(C) Colleague consultation may inform the report but doesn't replace it\n(D) Waiting for proof may endanger the elder — suspicion suffices"},
        {domainId:8, q:"APA Standard 3.04 regarding avoiding harm states that psychologists take reasonable steps to:", options:["Intentionally strategically deliberately cause emotional harm whenever clinically theoretically deemed absolutely strictly scientifically structurally necessary","Avoid, minimize, and not participate in activities likely to lead to harm to clients, students, research participants, or others","Systematically completely intentionally profoundly overwhelmingly ignore all potentially complex dangerous distressing harmful situational interactions","Abdicating transferring delegating reassigning encompassing rigorous overarching harm prevention responsibilities toward different professionals"], answer:1, difficulty:"easy", rationale:"Correct: (B) Standard 3.04: psychologists take reasonable steps to avoid, minimize, and not participate in causing harm. Where harm is foreseeable and unavoidable, the psychologist acts to minimize it. This includes being aware of how their own issues might affect their work.\n\nWhy others are wrong:\n(A) Causing harm is contrary to the standard\n(C) Active prevention is required\n(D) The psychologist bears personal responsibility"},
        {domainId:8, q:"Fee-splitting (receiving payment for referring a client) is:", options:["Universally conditionally appropriately broadly generally ethically comprehensively officially explicitly considered fundamentally completely acceptable","Generally prohibited — APA Standard 6.07 states psychologists do not pay or receive payment for client referrals","Statutorily institutionally mandatorily fundamentally strictly required uniformly across all specific regional comprehensive geographical legal boundaries","Exclusively uniquely systematically selectively rigidly categorically completely fully strictly prohibited only toward acting practicing psychiatrists"], answer:1, difficulty:"medium", rationale:"Correct: (B) Standard 6.07: referral fees are prohibited because they create financial incentives that may compromise clinical judgment. The referral should be based on client need, not financial gain. Exception: contractual employment arrangements.\n\nWhy others are wrong:\n(A) Fee-splitting is generally prohibited\n(C) It's prohibited by ethical standards, not required by law\n(D) The prohibition applies to psychologists and many other professionals"},
        {domainId:8, q:"Cultural competence in psychology requires:", options:["Consistently systematically fundamentally rigorously essentially formally clinically definitively treating absolutely everyone identically exactly equally","Awareness of one's own cultural values and biases, knowledge of diverse worldviews, and skills for culturally appropriate interventions","Universally functionally thoroughly actively entirely completely deliberately ignoring dismissing extensive complex varying individual cultural backgrounds","Strategically ethically professionally uniformly exclusively purely strictly working specifically alongside homogenous deeply similar client populations"], answer:1, difficulty:"easy", rationale:"Correct: (B) Sue's tripartite model: (1) Self-awareness (own cultural values, biases, assumptions), (2) Knowledge (understanding diverse worldviews, culture-specific psychological processes), (3) Skills (culturally appropriate interventions, communication styles). An ongoing developmental process, not an endpoint.\n\nWhy others are wrong:\n(A) Cultural blindness ('treating everyone the same') ignores important differences\n(C) Cultural differences significantly affect assessment, diagnosis, and treatment\n(D) Cultural competence enables working effectively across backgrounds"},

        // === Clinical Subtleties (15) ===
        {domainId:7, q:"Prolonged Grief Disorder (DSM-5-TR) requires:", options:["Standard normative bereavement patterns that predictably emerge following any significant interpersonal loss, typically resolving naturally without clinical intervention","Intense grief persisting beyond 12 months in adults (6 months in children) with yearning/preoccupation, significant functional impairment, and symptoms beyond cultural norms","A concentrated initial acute phase characterized by profound impairment and yearning that completely resolves within the first month following the traumatic event","Severe debilitating emotional dysregulation and intense longing that presents exclusively following the unexpected traumatic death of a primary spousal partner"], answer:1, difficulty:"medium", rationale:"Correct: (B) DSM-5-TR (2022): new diagnosis. Duration: ≥12 months adults, ≥6 months children/adolescents after death of someone close. Symptoms: intense yearning/longing, preoccupation with the deceased, identity disruption, avoidance of reminders, emotional numbness, loneliness, meaninglessness.\n\nWhy others are wrong:\n(A) Normal grief is not pathologized\n(C) The duration criterion is 12 months (adults)\n(D) It applies to the death of any close person"},
        {domainId:7, q:"Conversion Disorder (Functional Neurological Symptom Disorder) involves:", options:["Deliberate intentional production or feigning of widespread comprehensive physical or physiological symptoms exclusively driven by identifiable external secondary gain motivations","Neurological symptoms (paralysis, seizures, blindness) that are INCOMPATIBLE with recognized neurological conditions and are not better explained by another disorder","A recurrent chronic pervasive pattern consisting exclusively of debilitating severe persistent localized migraine headaches leading to extreme vocational impairment","A comprehensive generalized subjective presentation consisting strictly of profound systemic persistent chronic fatigue manifesting across multiple bodily systems"], answer:1, difficulty:"medium", rationale:"Correct: (B) Conversion disorder: neurological symptoms (motor or sensory) without identified neurological pathology. DSM-5 removed the requirement of identifying a psychological stressor. Key: clinical findings show INCOMPATIBILITY with neurological disease (e.g., Hoover's sign). Not intentional.\n\nWhy others are wrong:\n(A) It's unintentional — faking → Factitious Disorder or Malingering\n(C)(D) Symptoms mimic neurological conditions (paralysis, seizures, blindness) rather than presenting as isolated generic headaches or diffuse fatigue"},
        {domainId:7, q:"Specific Learning Disorder with impairment in mathematics (dyscalculia) involves:", options:["A broad generalized developmental deficit characterized strictly by significantly subaverage intellectual functioning and comprehensive adaptive behavioral limitations","Difficulties with number sense, memorization of arithmetic facts, fluent calculation, and/or mathematical reasoning, disproportionate to overall intellectual ability","A highly specific isolated profound neurodevelopmental deficiency exclusively affecting phonological processing, word recognition, and reading comprehension fluency","A pervasive overarching neurobehavioral pattern defined fundamentally by severe oppositional, defiant, and disruptively aggressive behavioral conduct problems"], answer:1, difficulty:"medium", rationale:"Correct: (B) Dyscalculia: specific deficit in mathematical processing. Not explained by intellectual disability, sensory deficits, or inadequate instruction. Subtypes: number sense/magnitude processing, arithmetic fact retrieval, mathematical procedures, mathematical reasoning.\n\nWhy others are wrong:\n(A) By definition, the difficulties are not due to low intellectual ability\n(C) Reading difficulties → dyslexia\n(D) While behavioral issues may co-occur, they're not the defining feature"},
        {domainId:7, q:"Selective Mutism is classified under:", options:["Communication Disorders in DSM-5 — characterized by foundational structural abnormalities in expressive language and speech fluency acquisition","Anxiety Disorders in DSM-5 — consistent failure to speak in specific social situations despite speaking in other situations, frequently with high comorbidity to social phobias","Personality Disorders in DSM-5 — featuring deeply ingrained inflexible childhood characteristics involving extreme interpersonal detachment and withdrawal","Psychotic Disorders in DSM-5 — defined by early-onset reality-testing disturbances causing profound generalized communication withdrawal processes"], answer:1, difficulty:"medium", rationale:"Correct: (B) Selective Mutism: reclassified from Communication Disorders to Anxiety Disorders in DSM-5. The child speaks at home but not at school/public. Duration ≥1 month (not the first month of school). Not due to communication disorder, ASD, or psychotic disorder. High comorbidity with Social Anxiety Disorder.\n\nWhy others are wrong:\n(A) It was moved FROM Communication Disorders in DSM-5\n(C)(D) It's classified under Anxiety Disorders"},
        {domainId:7, q:"The difference between delirium and dementia is:", options:["Delirium and dementia are essentially identical pathological neurocognitive diagnostic entities distinguished solely by patient age at the initial clinical presentation","Delirium is ACUTE onset with FLUCTUATING consciousness and attention, while dementia is CHRONIC progressive cognitive decline with typically preserved consciousness","Delirium precisely mirrors dementia in all clinical symptomatic presentations with the sole distinguishing factor being the overall comprehensive temporal duration","Delirium represents an entirely distinct pharmacological treatment approach while sharing fundamentally identical underlying neurobiological disease pathogeneses"], answer:1, difficulty:"medium", rationale:"Correct: (B) Delirium: acute (hours to days), fluctuating, affects consciousness/attention, often reversible (treat underlying cause — infection, medication, metabolic). Dementia (major NCD): chronic (months to years), progressive, consciousness usually clear initially, often irreversible. Delirium can be superimposed on dementia.\n\nWhy others are wrong:\n(A) They are distinct clinical entities\n(C) Onset, course, consciousness, and etiology all differ\n(D) Both differ across fundamentally diverse presentations, etiologies, courses, and treatments"},
        {domainId:7, q:"Borderline Personality Disorder (BPD) according to DSM-5 requires:", options:["A highly specific circumscribed presentation requiring exactly one singular isolated core diagnostic criterion demonstrating extreme profound emotional reactivity","A pervasive pattern of instability in interpersonal relationships, self-image, and affects, plus marked impulsivity, as indicated by 5 or more of 9 criteria","A consistent steady enduring trait-level manifestation strictly constrained entirely to cyclical unpredictable unprovoked rapid structural mood state instability","A comprehensive chronic pattern exclusively defined by repetitive systematic planned non-suicidal self-injurious behavioral manifestations without emotional shifts"], answer:1, difficulty:"medium", rationale:"Correct: (B) BPD criteria: frantic avoidance of abandonment, unstable relationships, identity disturbance, impulsivity, recurrent suicidal/self-harming behavior, affective instability, chronic emptiness, intense anger, transient paranoia/dissociation. ≥5 of 9 required. 75% diagnosed are female (though this may reflect diagnostic bias).\n\nWhy others are wrong:\n(A) At least 5 of 9 criteria are needed\n(C) Mood instability is one of several criteria\n(D) Self-harm is one criterion among nine"},
        {domainId:7, q:"Autism Spectrum Disorder (ASD) in DSM-5 requires deficits in:", options:["A solitary distinct diagnostic requirement centering exclusively upon profound delays in expressive and receptive spoken continuous language developmental milestones","Two domains: (1) social communication/interaction AND (2) restricted, repetitive patterns of behavior, interests, or activities","A singular overarching behavioral necessity focusing fundamentally upon uncontrollable impulsive externalizing hyperactive physical structural conduct manifestations","An isolated singular neurodevelopmental impairment primarily concerning gross and fine neuromuscular functional coordination and physical motor planning activities"], answer:1, difficulty:"easy", rationale:"Correct: (B) DSM-5 ASD: combines DSM-IV's Autistic Disorder, Asperger's, and PDD-NOS into one spectrum. Criterion A: social communication deficits (social-emotional reciprocity, nonverbal communication, relationships). Criterion B: restricted/repetitive behaviors, interests, activities. Three severity levels.\n\nWhy others are wrong:\n(A) Language delays are common but not required\n(C) Both social communication AND restricted behaviors are required\n(D) Motor stereotypies may be present but motor function isn't a diagnostic criterion"},
        {domainId:7, q:"Excoriation (Skin-Picking) Disorder is classified under:", options:["Anxiety Disorders in DSM-5, alongside conditions featuring excessive persistent fear, generalized apprehensive worry, and somatic hyperarousal behavioral disturbances","Obsessive-Compulsive and Related Disorders in DSM-5, alongside body dysmorphic disorder, hoarding disorder, and trichotillomania (hair-pulling disorder)","Personality Disorders in DSM-5, alongside enduring inflexible pervasive maladaptive psychological experiences and structural interpersonal behavioral functioning patterns","Substance-Related and Addictive Disorders in DSM-5, alongside compulsive physiological dependency syndromes and severe neurobiological behavioral addiction processes"], answer:1, difficulty:"easy", rationale:"Correct: (B) Excoriation disorder (new in DSM-5): recurrent skin picking causing lesions, repeated attempts to decrease/stop, and clinically significant distress/impairment. Classified with OCD, Trichotillomania (hair-pulling), Body Dysmorphic Disorder, and Hoarding Disorder.\n\nWhy others are wrong:\n(A) It's in the OCD chapter, not Anxiety\n(C) It's not a Personality Disorder\n(D) It's not substance-related"},
        {domainId:7, q:"Neurocognitive disorder due to Lewy body disease features:", options:["An exclusive distinct profound deficit strictly limited entirely to profound accelerating progressive anterograde explicit short-term declarative memory loss","Fluctuating cognition, visual hallucinations, parkinsonism, and REM sleep behavior disorder — with sensitivity to antipsychotic medications","A pervasive persistent mood disturbance characterized exclusively by profound chronic systemic intractable unremitting generalized clinical depressive symptoms","An overwhelming systemic physiological state characterized specifically by relentless excessive uncontrollable continuous generalized sympathetic anxiety arousal"], answer:1, difficulty:"hard", rationale:"Correct: (B) Lewy Body Dementia: alpha-synuclein protein deposits. Core features: fluctuating attention/cognition, recurrent detailed visual hallucinations, and REM Sleep Behavior Disorder (acting out dreams). Parkinsonism (bradykinesia, rigidity). CRITICAL: extreme sensitivity to antipsychotics (can cause severe neuroleptic malignant syndrome).\n\nWhy others are wrong:\n(A) Memory loss is present but isn't the distinguishing feature\n(C)(D) Psychiatric symptoms occur but aren't the primary diagnostic features"},
        {domainId:7, q:"Illness Anxiety Disorder differs from Somatic Symptom Disorder in that:", options:["They are essentially identical equivalent diagnostic clinical entities differentiated systematically only by specific organizational structural classification codes","Illness Anxiety Disorder involves preoccupation with HAVING or ACQUIRING a serious illness with minimal or absent somatic symptoms","They are fundamentally distinguished exclusively by the precise standardized clinical measurement of exact quantitative somatic symptom severity presentation","They are differentiated solely by their respective responsiveness towards divergent highly specific intensive psychopharmacological medical treatment approaches"], answer:1, difficulty:"medium", rationale:"Correct: (B) Illness Anxiety Disorder: anxiety about having a serious disease, with MINIMAL somatic symptoms (if symptoms are present and prominent → Somatic Symptom Disorder). Health preoccupation, easily alarmed about health status, excessive health-related behaviors (checking) or maladaptive avoidance.\n\nWhy others are wrong:\n(A) They differ in the prominence of somatic symptoms\n(C)(D) The distinction is primarily about symptom presence and focus"},
        {domainId:7, q:"The difference between Bipolar I and Bipolar II is:", options:["They represent entirely identical neurobiological mood spectra separated arbitrarily strictly through differing specific diagnostic institutional structural categorizations","Bipolar I requires at least one MANIC episode (may have depressive episodes), while Bipolar II requires at least one HYPOMANIC episode AND one major depressive episode","Bipolar II fundamentally systematically represents a consistently significantly more severe profound clinical symptomatic presentation than typical classical Bipolar I","They are actively differentiated explicitly and exclusively based upon their specific specialized long-term maintenance pharmacological medication treatment regimens"], answer:1, difficulty:"easy", rationale:"Correct: (B) Bipolar I: full manic episodes (≥7 days or hospitalization) — depressive episodes are common but NOT required for diagnosis. Bipolar II: hypomanic episodes (≥4 days, less severe, no hospitalization/psychosis) PLUS ≥1 major depressive episode. Bipolar II is NOT a milder form — depression is often severe.\n\nWhy others are wrong:\n(A) They are distinct diagnoses\n(C) Bipolar II is not necessarily less severe — it has significant depressive burden\n(D) They differ in diagnostic criteria, not just treatment"},
        {domainId:7, q:"Hoarding Disorder in DSM-5 is characterized by:", options:["An exclusive sophisticated systematic behavioral tendency selectively focused entirely upon selectively acquiring securing extremely rare highly valuable artistic items","Persistent difficulty discarding possessions regardless of actual value, with distress associated with discarding, resulting in accumulation that clutters living areas","A highly structured meticulous organized systematic categorization process ensuring flawlessly cataloged extensive comprehensive functional personal historical collections","A pervasive persistent continuous behavior characterized explicitly and exclusively by actively acquiring gaining accumulating new possessions without retention issues"], answer:1, difficulty:"easy", rationale:"Correct: (B) Hoarding Disorder (new as standalone in DSM-5): difficulty discarding + distress about discarding + cluttered living spaces. May have excessive acquisition (buying, free items). Specifiers: with excessive acquisition, poor insight. Not due to another condition. Prevalence 2-6%.\n\nWhy others are wrong:\n(A) The items' actual value is irrelevant\n(C) The defining feature is inability to discard, with resulting clutter\n(D) Difficulty discarding is the core feature, though excessive acquiring often co-occurs"},
        {domainId:7, q:"Persistent Depressive Disorder (Dysthymia) requires:", options:["A transient brief rapid affective cognitive deterioration strictly limited specifically to requiring exactly one single continuous continuous uninterrupted calendar week","Depressed mood for MOST of the day, for MORE DAYS THAN NOT, for at least 2 YEARS in adults (1 year in children/adolescents)","A distinct explicitly circumscribed moderately intense depressive episode systematically requiring an exact absolute continuous duration of exactly one singular month","An overwhelming profoundly debilitating paralyzing severe major depressive presentation necessitating absolute complete pervasive structural functional incapacitation"], answer:1, difficulty:"easy", rationale:"Correct: (B) PDD (DSM-5 merged dysthymic disorder and chronic MDD): ≥2 years duration, not symptom-free for more than 2 months at a time. At least 2 additional symptoms (appetite, sleep, energy, self-esteem, concentration, hopelessness). Can have major depressive episodes superimposed ('double depression').\n\nWhy others are wrong:\n(A) The duration criterion is 2 years\n(C) 1 month is insufficient\n(D) PDD can be mild to moderate — doesn't require severe depression"},
        {domainId:7, q:"Intermittent Explosive Disorder requires:", options:["A distinct systematic singular isolated solitary uncontrollable intense extreme aggressive psychological outburst occurring exactly once throughout the entire lifespan","Recurrent behavioral outbursts representing a failure to control aggressive impulses, grossly disproportionate to the provocation or stressor","A persistent continuous structural psychological pattern exclusively utilizing profound intense verbal aggression while completely avoiding all physical manifestations","A highly calculated meticulously strategically planned deeply systematic intentional premeditated pattern featuring orchestrated targeted physical violent aggression"], answer:1, difficulty:"medium", rationale:"Correct: (B) IED: recurrent impulsive (not premeditated) aggressive outbursts — verbal (verbal tirades) or physical (property damage, physical assault). Must be grossly disproportionate. Either: ≥2 outbursts involving physical damage in 12 months, OR ≥3 tantrums/tirades weekly for 3 months.\n\nWhy others are wrong:\n(A) Recurrent outbursts are required\n(C) Both verbal and physical aggression qualify\n(D) IED is specifically about IMPULSIVE aggression, not planned violence"},
        {domainId:7, q:"The key feature distinguishing Schizophreniform Disorder from Schizophrenia is:", options:["SYMPTOM PRESENTATION — Schizophreniform selectively features prominent predominant negative symptoms while Schizophrenia invariably necessitates active florid positive acute psychotic hallucinations","DURATION AND IMPAIRMENT — Schizophreniform Disorder lasts between 1-6 months without requiring functional decline, while Schizophrenia requires symptoms for ≥6 months with marked impairment","TREATMENT PARADIGMS — Schizophreniform Disorder specifically requires immediate intensive acute hospitalization while Schizophrenia mandates exclusively ongoing outpatient maintenance psychopharmacology","ONSET TIMELINE — Schizophreniform systematically initially emerges exclusively during early early childhood whereas Schizophrenia fundamentally presents strictly throughout late middle adulthood epochs"], answer:1, difficulty:"easy", rationale:"Correct: (B) Same symptoms as Schizophrenia (≥2 of: delusions, hallucinations, disorganized speech, disorganized/catatonic behavior, negative symptoms) but total duration ≥1 month and <6 months. If symptoms persist past 6 months, diagnosis changes to Schizophrenia. Functional decline not required.\n\nWhy others are wrong:\n(A) The symptom criteria are the same\n(C) Treatment may be similar but the diagnostic distinction is duration\n(D) The key distinction is duration, not age of onset"}
    ];

    batch51.forEach(q => {
        const domain = EPPPData.domains.find(d => d.id === q.domainId);
        if (domain) {
            domain.questions.push({
                q: q.q, options: q.options, answer: q.answer,
                difficulty: q.difficulty, rationale: q.rationale,
                domainId: q.domainId, domainName: domain.name
            });
        }
    });

    console.log(`PasstheEPPP: Loaded ${batch51.length} additional questions (batch 51).`);
})();
